"use client";
import React, { useState, useRef, useEffect } from "react";

const VisaCategorySelect: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState("Travel Visa");
  const dropdownRef = useRef<HTMLDivElement>(null);

  const categories: string[] = [
    "Travel Visa",
    "Business Visa",
    "Student Visa",
    "Work Visa",
    "Medical Visa",
  ];

  // Close dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node)
      ) {
        setIsOpen(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSelect = (category: string) => {
    setSelectedCategory(category);
    setIsOpen(false);
  };

  return (
    <div className="single-search-box" ref={dropdownRef}>
        <svg width={16} height={18} viewBox="0 0 16 18" xmlns="http://www.w3.org/2000/svg">
                <path fillRule="evenodd" clipRule="evenodd" d="M11.3652 14.3217C11.3652 14.4501 11.2588 14.5565 11.1304 14.5565H2.9913C2.86295 14.5565 2.75651 14.4501 2.75651 14.3217C2.75651 14.1934 2.86295 14.087 2.9913 14.087H11.1304C11.2588 14.087 11.3652 14.1934 11.3652 14.3217ZM15.7478 1.17391V16.8261C15.7478 17.136 15.6226 17.4365 15.4035 17.6557C15.1843 17.8748 14.8838 18 14.5739 18H1.42608C1.11617 18 0.815645 17.8748 0.596515 17.6557C0.374254 17.4365 0.252167 17.136 0.252167 16.8261V1.17391C0.252167 0.86087 0.374254 0.563478 0.596515 0.344348C0.815645 0.122087 1.11617 0 1.42608 0H14.5739C14.8838 0 15.1843 0.122087 15.4035 0.344348C15.6226 0.563478 15.7478 0.86087 15.7478 1.17391ZM13.4 1.17391C13.4 0.986087 13.3249 0.807652 13.1934 0.676174C13.0619 0.544696 12.8835 0.469565 12.6956 0.469565H1.42608C1.23825 0.469565 1.05982 0.544696 0.928341 0.676174C0.796862 0.807652 0.721732 0.986087 0.721732 1.17391V16.8261C0.721732 17.0139 0.796862 17.1923 0.928341 17.3238C1.05982 17.4553 1.23825 17.5304 1.42608 17.5304H12.6956C12.8835 17.5304 13.0619 17.4553 13.1934 17.3238C13.3249 17.1923 13.4 17.0139 13.4 16.8261V1.17391ZM3.06956 5.86957C3.06956 3.66574 4.85704 1.87826 7.06086 1.87826C9.26469 1.87826 11.0522 3.66574 11.0522 5.86957C11.0522 8.07339 9.26469 9.86087 7.06086 9.86087C4.85704 9.86087 3.06956 8.07339 3.06956 5.86957ZM7.97495 8.76835C8.22225 8.40522 8.41947 7.92 8.54782 7.35652H5.57391C5.70225 7.92 5.89947 8.40522 6.14678 8.76835C6.4066 9.15026 6.71338 9.3913 7.06086 9.3913C7.40834 9.3913 7.71512 9.15026 7.97495 8.76835ZM8.63234 6.88696C8.6793 6.56452 8.70434 6.2233 8.70434 5.86957C8.70434 5.51583 8.6793 5.17461 8.63234 4.85217H5.48938C5.44243 5.17461 5.41738 5.51583 5.41738 5.86957C5.41738 6.2233 5.44243 6.56452 5.48938 6.88696H8.63234ZM10.2539 7.35652H9.02678C8.88591 8.02956 8.65425 8.6087 8.36312 9.03444C8.32869 9.08452 8.29112 9.13461 8.25356 9.1847C9.13947 8.86539 9.85947 8.20174 10.2539 7.35652ZM10.4323 4.85217H9.10504C9.14886 5.17774 9.17391 5.51896 9.17391 5.86957C9.17391 6.22017 9.14886 6.56139 9.10504 6.88696H10.4323C10.6324 6.22345 10.6324 5.51568 10.4323 4.85217ZM8.25356 2.55443C8.29112 2.60452 8.32869 2.65461 8.36312 2.7047C8.65425 3.13043 8.88591 3.70957 9.02678 4.38261H10.2539C9.85947 3.53739 9.13947 2.87374 8.25356 2.55443ZM6.14678 2.97078C5.89947 3.33391 5.70225 3.81913 5.57391 4.38261H8.54782C8.41947 3.81913 8.22225 3.33391 7.97495 2.97078C7.71512 2.58887 7.40834 2.34783 7.06086 2.34783C6.71338 2.34783 6.4066 2.58887 6.14678 2.97078ZM3.86782 4.38261H5.09808C5.23582 3.70957 5.46747 3.13043 5.7586 2.7047C5.79304 2.65461 5.8306 2.60452 5.86817 2.55443C5.43091 2.71266 5.02915 2.95557 4.6859 3.26928C4.34265 3.58298 4.06465 3.96132 3.86782 4.38261ZM3.68938 6.88696H5.01669C4.97286 6.56139 4.94782 6.22017 4.94782 5.86957C4.94782 5.51896 4.97286 5.17774 5.01669 4.85217H3.68938C3.48929 5.51568 3.48929 6.22345 3.68938 6.88696ZM3.86782 7.35652C4.26225 8.20174 4.98225 8.86539 5.86817 9.1847C5.8306 9.13461 5.79304 9.08452 5.7586 9.03444C5.46747 8.6087 5.23582 8.02956 5.09808 7.35652H3.86782ZM11.1304 15.3391H2.9913C2.86295 15.3391 2.75651 15.4456 2.75651 15.5739C2.75651 15.7023 2.86295 15.8087 2.9913 15.8087H11.1304C11.2588 15.8087 11.3652 15.7023 11.3652 15.5739C11.3652 15.4456 11.2588 15.3391 11.1304 15.3391Z" />
              </svg>
      <div
        className="custom-select-dropdown"
        onClick={() => setIsOpen((prev) => !prev)}
      >
        <input type="text" readOnly value={selectedCategory} />
        <span>Category</span>
      </div>

      <div
        className={`custom-select-wrap two ${isOpen ? "active" : ""}`}
      >
        <ul className="option-list">
          {categories.map((category) => (
            <li
              key={category}
              className="single-item"
              onClick={() => handleSelect(category)}
            >
              <h6>{category}</h6>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default VisaCategorySelect;
